import{_ as t,c as o,o as a,a1 as n}from"./chunks/framework.DDNAyvCW.js";const s="/assets/autocomplete.2HpzC-QQ.png",h=JSON.parse('{"title":"Command Autocomplete","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/autocomplete/index.md","filePath":"docs/terminal/autocomplete/index.md"}'),i={name:"docs/terminal/autocomplete/index.md"};function r(l,e,d,c,m,u){return a(),o("div",null,e[0]||(e[0]=[n('<h1 id="command-autocomplete" tabindex="-1">Command Autocomplete <a class="header-anchor" href="#command-autocomplete" aria-label="Permalink to &quot;Command Autocomplete&quot;">​</a></h1><p>Chaterm suggests commands as you type in the terminal, helping you work faster and reducing typos by drawing from your history, a built-in command library, and optional AI suggestions.</p><p><img src="'+s+'" alt=""></p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Autocomplete combines three sources to generate suggestions:</p><ul><li><strong>Command History</strong> -- prioritizes commands you have used on the current server, then supplements with frequently used commands from your other servers (cross-host recommendations).</li><li><strong>Built-in Command Library</strong> -- common Linux and shell commands are always available as suggestions.</li><li><strong>AI Smart Suggestions (Optional)</strong> -- generates context-aware command completions based on your current input.</li></ul><p>Cross-host recommendations match the current server&#39;s usage patterns first, then fill in with related commands you frequently use on other servers.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><ol><li>Start typing a command in the terminal. The autocomplete panel appears automatically.</li><li>Press <code>→</code> (right arrow) to enter selection mode.</li><li>Press <code>↑</code> / <code>↓</code> to navigate between suggestions.</li><li>Press <code>Enter</code> to confirm and insert the selected command.</li><li>Press <code>Esc</code> or <code>←</code> (left arrow) to exit selection mode or close the panel.</li></ol><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>→</code></td><td>Enter selection mode</td></tr><tr><td><code>↑</code> / <code>↓</code></td><td>Navigate between suggestions</td></tr><tr><td><code>Enter</code></td><td>Confirm and insert the selected command</td></tr><tr><td><code>Esc</code></td><td>Close the autocomplete panel</td></tr><tr><td><code>←</code></td><td>Exit selection mode</td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>You can enable or disable autocomplete in <strong>Settings &gt; Extension Settings</strong>:</p><ul><li><strong>Enabled</strong> (recommended) -- shows autocomplete suggestions while you type.</li><li><strong>Disabled</strong> -- hides the autocomplete panel entirely; you type commands manually.</li></ul><p>For details on locating this toggle, see <a href="/docs/settings/extensions/">Extension Settings</a>.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="the-autocomplete-panel-is-not-showing-up" tabindex="-1">The autocomplete panel is not showing up <a class="header-anchor" href="#the-autocomplete-panel-is-not-showing-up" aria-label="Permalink to &quot;The autocomplete panel is not showing up&quot;">​</a></h3><ul><li>Confirm that <strong>Autocomplete</strong> is enabled in <strong>Settings &gt; Extension Settings</strong>.</li><li>Type at least one character and wait briefly for suggestions to appear.</li><li>If the panel still does not appear, try restarting the terminal session.</li></ul><h3 id="ai-suggestions-are-not-appearing" tabindex="-1">AI suggestions are not appearing <a class="header-anchor" href="#ai-suggestions-are-not-appearing" aria-label="Permalink to &quot;AI suggestions are not appearing&quot;">​</a></h3><ul><li>AI suggestions require a network connection. Local autocomplete (history and built-in commands) continues to work offline.</li><li>Check that AI features are enabled in your settings.</li></ul><h3 id="suggestions-seem-irrelevant" tabindex="-1">Suggestions seem irrelevant <a class="header-anchor" href="#suggestions-seem-irrelevant" aria-label="Permalink to &quot;Suggestions seem irrelevant&quot;">​</a></h3><ul><li>Autocomplete improves over time as it learns from your command history.</li><li>Cross-host suggestions may surface commands from other servers. If a suggestion does not apply, simply ignore it and keep typing.</li></ul>',21)]))}const p=t(i,[["render",r]]);export{h as __pageData,p as default};
